import { useState, useEffect, useLayoutEffect } from 'react';

function Timer() {
  const [seconds, setSeconds] = useState(0);

  // Runs once after mount (empty dependency array)
  useEffect(() => {
    console.log('mounted — starting interval');
    const id = setInterval(() => setSeconds((s) => s + 1), 1000);

    // Cleanup runs on unmount
    return () => {
      console.log('unmounted — clearing interval');
      clearInterval(id);
    };
  }, []);

  return <p>{seconds}s elapsed</p>;
}

function Profile({ userId }) {
  const [user, setUser] = useState(null);

  // Re-runs whenever userId changes
  useEffect(() => {
    let cancelled = false;
    fetchUser(userId).then((data) => {
      if (!cancelled) setUser(data);
    });

    // Cleanup cancels the previous fetch when userId changes
    return () => { cancelled = true; };
  }, [userId]); // ← dependency — effect re-runs when this changes

  if (!user) return <p>Loading…</p>;
  return <h1>{user.name}</h1>;
}

function ChatRoom({ roomId }) {
  useEffect(() => {
    const socket = createSocket(roomId);
    socket.connect();

    return () => {
      // Cleanup: runs when roomId changes OR when component unmounts
      socket.disconnect();
    };
  }, [roomId]);

  return <p>Connected to {roomId}</p>;
}

// Wrong: runs after every render — probably unintentional
useEffect(() => {
  document.title = user.name;
}); // no array

// Correct: update title only when user.name changes
useEffect(() => {
  document.title = user.name;
}, [user.name]);

// Runs once on mount (subscribe) and once on unmount (unsubscribe)
useEffect(() => {
  const sub = store.subscribe(handler);
  return () => sub.unsubscribe();
}, []);

function App() {
  const [showPanel, setShowPanel] = useState(false);

  return (
    <div>
      <button onClick={() => setShowPanel(!showPanel)}>Toggle</button>
      {/* Panel mounts when showPanel becomes true, unmounts when false */}
      {showPanel && <Panel />}
    </div>
  );
}

// Force a fresh mount (and state reset) by changing key
<Form key={formVersion} />

// Increment formVersion to reset the form entirely:
<button onClick={() => setFormVersion((v) => v + 1)}>Reset form</button>

// In development with StrictMode:
useEffect(() => {
  console.log('setup');
  return () => console.log('cleanup');
}, []);
// Console output on mount:
// setup
// cleanup    ← StrictMode unmounts and remounts
