// In production: only "setup" once on mount

// The setup function returns the cleanup function
useEffect(() => {
  // Setup: acquire a resource
  const subscription = eventSource.subscribe(handler);

  // Cleanup: release the resource (returned from setup)
  return () => {
    subscription.unsubscribe();
  };
}, []);

// Multiple cleanups in one effect
useEffect(() => {
  const timer = setInterval(tick, 1000);
  window.addEventListener('resize', onResize);

  return () => {
    clearInterval(timer);
    window.removeEventListener('resize', onResize);
  };
}, []);

// The component function MUST be pure — it can be called multiple times
// without any visible side effects to the user

function PureComponent({ data }) {
  // OK: local computation, no external mutation
  const processed = data.map(transform);
  return <ul>{processed.map((item) => <li key={item.id}>{item.name}</li>)}</ul>;
}

// Wrong: mutation during render breaks concurrency
let count = 0;
function ImpureComponent() {
  count++; // ← side effect during render — will double-count in concurrent mode
  return <p>Rendered {count} times</p>;
}

function DebugComponent({ id }) {
  console.log(`[RENDER] id=${id}`);

  useLayoutEffect(() => {
    console.log(`[LAYOUT-EFFECT SETUP] id=${id}`);
    return () => console.log(`[LAYOUT-EFFECT CLEANUP] id=${id}`);
  }, [id]);

  useEffect(() => {
    console.log(`[EFFECT SETUP] id=${id}`);
    return () => console.log(`[EFFECT CLEANUP] id=${id}`);
  }, [id]);

  return <p>id: {id}</p>;
}

// Mounting with id=1, then updating to id=2 produces:
// [RENDER] id=1
// [LAYOUT-EFFECT SETUP] id=1
// [EFFECT SETUP] id=1
// [RENDER] id=2
// [LAYOUT-EFFECT CLEANUP] id=1
// [LAYOUT-EFFECT SETUP] id=2
// [EFFECT CLEANUP] id=1
// [EFFECT SETUP] id=2

// Cancellation pattern for async effects
useEffect(() => {
  let cancelled = false;

  async function load() {
    const data = await fetch('/api/data').then((r) => r.json());
    if (!cancelled) {
      setData(data);
    }
  }

  load();

  return () => { cancelled = true; };
}, []);

// With AbortController (preferred for fetch)
useEffect(() => {
  const controller = new AbortController();

  fetch('/api/data', { signal: controller.signal })
    .then((r) => r.json())
    .then(setData)
    .catch((err) => {
      if (err.name !== 'AbortError') throw err;
    });

  return () => controller.abort();
}, []);

// Reusable subscription hook
function useEventListener(target, event, handler) {
  useEffect(() => {
    target.addEventListener(event, handler);
    return () => target.removeEventListener(event, handler);
  }, [target, event, handler]);
}

// Reusable data fetching hook
function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const controller = new AbortController();
    setLoading(true);

    fetch(url, { signal: controller.signal })
      .then((r) => r.json())
      .then((d) => { setData(d); setLoading(false); })
      .catch((err) => { if (err.name !== 'AbortError') setLoading(false); });

    return () => controller.abort();
  }, [url]);

  return { data, loading };
}

// In a component — mount, update, and cleanup are handled by the hook
function Page({ id }) {
  const { data, loading } = useFetch(`/api/items/${id}`);
  if (loading) return <p>Loading…</p>;
  return <pre>{JSON.stringify(data, null, 2)}</pre>;
}

import { render, screen, act } from '@testing-library/react';
import { Timer } from './Timer';

test('starts counting after mount', async () => {
  jest.useFakeTimers();

  render(<Timer />);
  expect(screen.getByText('0s elapsed')).toBeInTheDocument();

  act(() => { jest.advanceTimersByTime(3000); });
  expect(screen.getByText('3s elapsed')).toBeInTheDocument();

  jest.useRealTimers();
});

test('clears interval on unmount', () => {
  const clearIntervalSpy = jest.spyOn(window, 'clearInterval');
  const { unmount } = render(<Timer />);

  unmount();

  expect(clearIntervalSpy).toHaveBeenCalled();
  clearIntervalSpy.mockRestore();
});
